	}
	if strings.Contains(logOutput, "#frag") {
		t.Errorf("verbose log leaked fragment: %q", logOutput)
	}
	if !strings.Contains(logOutput, "/secret/path") {
		t.Errorf("verbose log missing sanitized path: %q", logOutput)
	}
}

