func TestURLFetch_AllowlistPermitsMatchingHost(t *testing.T) {
	ts := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		w.WriteHeader(200)
		_, _ = w.Write([]byte("ok"))
	}))
	defer ts.Close()

	// Extract hostname from test server URL
	u, _ := url.Parse(ts.URL)
	hostname := u.Hostname()

	// Override host check to allow the test server's private IP through
	orig := urlFetchCheckHost
	urlFetchCheckHost = func(ctx context.Context, h string, allowlist []string, resolver hostcheck.Resolver) (net.IP, error) {
		return hostcheck.CheckHost(ctx, h, allowlist, resolver)
	}
	defer func() { urlFetchCheckHost = orig }()

	// Override resolver to return a public IP so CheckHost passes private IP gate,
	// but we need the actual connection to reach the test server. Since the test
	// server URL uses the raw IP 127.0.0.1, CheckHost will parse it as a raw IP
	// literal and block it. Instead, we bypass CheckHost for the allowlist test
	// and only verify the allowlist logic: if hostname is in allowlist, request succeeds.
	urlFetchCheckHost = func(ctx context.Context, h string, allowlist []string, resolver hostcheck.Resolver) (net.IP, error) {
		if !hostcheck.IsAllowed(h, allowlist) {
			return nil, &net.OpError{Op: "check", Err: &net.AddrError{Err: "not in allowed_hosts", Addr: h}}
		}
		return net.ParseIP("127.0.0.1"), nil
	}

	entry := urlFetchEntry()
	result := entry.Execute(context.Background(), provider.ToolCall{
		ID:        "test-1",
		Name:      "url_fetch",
		Arguments: map[string]string{"url": ts.URL},
	}, ExecContext{AllowedHosts: []string{hostname}})

	if result.IsError {
		t.Errorf("expected success, got error: %s", result.Content)
	}
}

